#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int isDelicious(long long num) {
    int digits[10] = {0};
    while (num > 0) {
        int digit = num % 10;
        if (digits[digit] == 1) return 0;
        digits[digit] = 1;
        num /= 10;
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long L, R;
        scanf("%lld %lld", &L, &R);
        long long count = 0;
        for (long long i = L; i <= R; i++) {
            if (isDelicious(i)) count++;
        }
        printf("%lld\n", count);
    }
    return 0;
}

