#include <iostream>
using namespace std;

bool isDelicious(long long num) {
    bool digits[10] = {false};
    while (num > 0) {
        int digit = num % 10;
        if (digits[digit]) return false;
        digits[digit] = true;
        num /= 10;
    }
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        long long L, R;
        cin >> L >> R;
        long long count = 0;
        for (long long i = L; i <= R; i++) {
            if (isDelicious(i)) count++;
        }
        cout << count << endl;
    }
    return 0;
}

code.Java:
import java.util.Scanner;

public class Main {
    public static boolean isDelicious(long num) {
        boolean[] digits = new boolean[10];
        while (num > 0) {
            int digit = (int) (num % 10);
            if (digits[digit]) return false;
            digits[digit] = true;
            num /= 10;
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            long L = scanner.nextLong();
            long R = scanner.nextLong();
            long count = 0;
            for (long i = L; i <= R; i++) {
                if (isDelicious(i)) count++;
            }
            System.out.println(count);
        }
    }
}

